import android.database.sqlite.SQLiteDatabase

/**
 * Fix folder selection settings to be MANUAL when folder names are configured.
 * 
 * This corrects cases where folder names are manually configured but the folder selection
 * setting is incorrectly set to AUTOMATIC (which can happen after importing settings from K-9).
 */
class StorageMigrationTo26(
    private val db: SQLiteDatabase,
    private val migrationsHelper: StorageMigrationHelper,
) {
    fun fixFolderSelectionSettings() {
        val accountUuidsListValue = migrationsHelper.readValue(db, "accountUuids")
        if (accountUuidsListValue == null || accountUuidsListValue.isEmpty()) {
            return
        }

        val accountUuids = accountUuidsListValue.split(",")
        for (accountUuid in accountUuids) {
            fixFolderSelectionForAccount(accountUuid)
        }
    }

    private fun fixFolderSelectionForAccount(accountUuid: String) {
        fixFolderSelection(accountUuid, "archiveFolderName", "archiveFolderSelection")
        fixFolderSelection(accountUuid, "draftsFolderName", "draftsFolderSelection")
        fixFolderSelection(accountUuid, "sentFolderName", "sentFolderSelection")
        fixFolderSelection(accountUuid, "spamFolderName", "spamFolderSelection")
        fixFolderSelection(accountUuid, "trashFolderName", "trashFolderSelection")
    }

