        // change it to MANUAL to honor the configured folder
        if (!folderName.isNullOrEmpty() && folderSelection == "AUTOMATIC") {
            migrationsHelper.writeValue(db, "$accountUuid.$folderSelectionKey", "MANUAL")
        }
    }
