344→    private static class IntegerArraySetting extends SettingsDescription<Integer> {
345→        private final int[] values;
346→
347→        IntegerArraySetting(int defaultValue, int[] values) {
348→            super(defaultValue);
349→            this.values = values;
350→        }
351→
352→        @Override
353→        public Integer fromString(String value) throws InvalidSettingValueException {
354→            try {
355→                int number = Integer.parseInt(value);
356→                for (int validValue : values) {
357→                    if (number == validValue) {
