import com.fsck.k9.preferences.CombinedSettingsUpgrader
import com.fsck.k9.preferences.ValidatedSettings

/**
 * Ensures folder selection settings are set to MANUAL when corresponding folder names are configured,
 * even if they were previously set to AUTOMATIC.
 *
 * This fixes imports from K-9 where folders were manually configured but folder selection settings
 * were incorrectly set to AUTOMATIC.
 */
class CombinedSettingsUpgraderTo101 : CombinedSettingsUpgrader {
    override fun upgrade(account: ValidatedSettings.Account): ValidatedSettings.Account {
        val settings = account.settings.toMutableMap()

        // For each special folder type, check if a folder name is configured
        // If so, ensure the folder selection is set to MANUAL
        correctFolderSelection(settings, "archiveFolderName", "archiveFolderSelection")
        correctFolderSelection(settings, "draftsFolderName", "draftsFolderSelection")
        correctFolderSelection(settings, "sentFolderName", "sentFolderSelection")
        correctFolderSelection(settings, "spamFolderName", "spamFolderSelection")
        correctFolderSelection(settings, "trashFolderName", "trashFolderSelection")

        return account.copy(settings = settings)
    }

    private fun correctFolderSelection(
        settings: MutableMap<String, Any?>,
        folderNameKey: String,
        folderSelectionKey: String
    ) {
        val folderName = settings[folderNameKey]
        val folderSelection = settings[folderSelectionKey]

        // If folder name is configured (not null and not empty) but selection is AUTOMATIC,
        // change it to MANUAL to honor the configured folder
        if (folderName != null && folderName.toString().isNotEmpty()) {
            if (folderSelection == "AUTOMATIC") {
                settings[folderSelectionKey] = "MANUAL"
            }
        }
    }
}
"}

