import android.database.sqlite.SQLiteDatabase
import assertk.assertThat
import assertk.assertions.isEqualTo
import assertk.assertions.isNull
import com.fsck.k9.preferences.createStorageDatabase
import org.junit.Test
import org.junit.runner.RunWith
import org.robolectric.RobolectricTestRunner

@RunWith(RobolectricTestRunner::class)
class StorageMigrationTo26Test {
    @Test
    fun `fixFolderSelectionSettings should change AUTOMATIC to MANUAL when folder name is configured`() {
        val db = createStorageDatabase()
        val migrationHelper = DefaultStorageMigrationHelper()

        // Set up account with configured folder names but AUTOMATIC selection
        migrationHelper.insertValue(db, "accountUuids", "test-uuid")
        migrationHelper.insertValue(db, "test-uuid.draftsFolderName", "Drafts")
        migrationHelper.insertValue(db, "test-uuid.draftsFolderSelection", "AUTOMATIC")
        migrationHelper.insertValue(db, "test-uuid.sentFolderName", "Sent")
        migrationHelper.insertValue(db, "test-uuid.sentFolderSelection", "AUTOMATIC")

        val migration = StorageMigrationTo26(db, migrationHelper)
        migration.fixFolderSelectionSettings()

        assertThat(migrationHelper.readValue(db, "test-uuid.draftsFolderSelection")).isEqualTo("MANUAL")
        assertThat(migrationHelper.readValue(db, "test-uuid.sentFolderSelection")).isEqualTo("MANUAL")
    }

    @Test
    fun `fixFolderSelectionSettings should not change MANUAL selection`() {
        val db = createStorageDatabase()
        val migrationHelper = DefaultStorageMigrationHelper()

        // Set up account with configured folder names and MANUAL selection
        migrationHelper.insertValue(db, "accountUuids", "test-uuid")
        migrationHelper.insertValue(db, "test-uuid.draftsFolderName", "Drafts")
        migrationHelper.insertValue(db, "test-uuid.draftsFolderSelection", "MANUAL")

        val migration = StorageMigrationTo26(db, migrationHelper)
        migration.fixFolderSelectionSettings()

        assertThat(migrationHelper.readValue(db, "test-uuid.draftsFolderSelection")).isEqualTo("MANUAL")
    }

    @Test
    fun `fixFolderSelectionSettings should not change AUTOMATIC when folder name is not configured`() {
        val db = createStorageDatabase()
        val migrationHelper = DefaultStorageMigrationHelper()

        // Set up account without configured folder name
        migrationHelper.insertValue(db, "accountUuids", "test-uuid")
        migrationHelper.insertValue(db, "test-uuid.draftsFolderSelection", "AUTOMATIC")

        val migration = StorageMigrationTo26(db, migrationHelper)
        migration.fixFolderSelectionSettings()

        assertThat(migrationHelper.readValue(db, "test-uuid.draftsFolderSelection")).isEqualTo("AUTOMATIC")
    }

    @Test
    fun `fixFolderSelectionSettings should handle empty folder name`() {
        val db = createStorageDatabase()
        val migrationHelper = DefaultStorageMigrationHelper()

        // Set up account with empty folder name
        migrationHelper.insertValue(db, "accountUuids", "test-uuid")
        migrationHelper.insertValue(db, "test-uuid.draftsFolderName", "")
        migrationHelper.insertValue(db, "test-uuid.draftsFolderSelection", "AUTOMATIC")

        val migration = StorageMigrationTo26(db, migrationHelper)
        migration.fixFolderSelectionSettings()

        assertThat(migrationHelper.readValue(db, "test-uuid.draftsFolderSelection")).isEqualTo("AUTOMATIC")
    }

    @Test
    fun `fixFolderSelectionSettings should handle multiple accounts`() {
        val db = createStorageDatabase()
        val migrationHelper = DefaultStorageMigrationHelper()

        // Set up two accounts
        migrationHelper.insertValue(db, "accountUuids", "uuid1,uuid2")
        migrationHelper.insertValue(db, "uuid1.draftsFolderName", "Drafts")
        migrationHelper.insertValue(db, "uuid1.draftsFolderSelection", "AUTOMATIC")
        migrationHelper.insertValue(db, "uuid2.sentFolderName", "Sent")
        migrationHelper.insertValue(db, "uuid2.sentFolderSelection", "AUTOMATIC")

        val migration = StorageMigrationTo26(db, migrationHelper)
        migration.fixFolderSelectionSettings()

        assertThat(migrationHelper.readValue(db, "uuid1.draftsFolderSelection")).isEqualTo("MANUAL")
        assertThat(migrationHelper.readValue(db, "uuid2.sentFolderSelection")).isEqualTo("MANUAL")
    }
}

private fun createStorageDatabase(): SQLiteDatabase {
    return SQLiteDatabase.create(null).also { db ->
        db.execSQL("CREATE TABLE preferences_storage (primkey TEXT PRIMARY KEY, value TEXT)")
    }
}
