 5→/**
 6→ * Fix folder selection settings to be MANUAL when folder names are configured.
 7→ *
 8→ * This corrects cases where folder names are manually configured but the folder selection
 9→ * setting is incorrectly set to AUTOMATIC (which can happen after importing settings from K-9).
10→ */
11→class StorageMigrationTo26(
12→    private val db: SQLiteDatabase,
13→    private val migrationsHelper: StorageMigrationHelper,
14→) {
15→    fun fixFolderSelectionSettings() {
16→        val accountUuidsListValue = migrationsHelper.readValue(db, "accountUuids")
17→        if (accountUuidsListValue == null || accountUuidsListValue.isEmpty()) {
18→            return
19→        }
20→
21→        val accountUuids = accountUuidsListValue.split(",")
22→        for (accountUuid in accountUuids) {
23→            fixFolderSelectionForAccount(accountUuid)
24→        }
25→    }
26→
27→    private fun fixFolderSelectionForAccount(accountUuid: String) {
28→        fixFolderSelection(accountUuid, "archiveFolderName", "archiveFolderSelection")
29→        fixFolderSelection(accountUuid, "draftsFolderName", "draftsFolderSelection")
30→        fixFolderSelection(accountUuid, "sentFolderName", "sentFolderSelection")
31→        fixFolderSelection(accountUuid, "spamFolderName", "spamFolderSelection")
32→        fixFolderSelection(accountUuid, "trashFolderName", "trashFolderSelection")
33→    }
34→
35→    private fun fixFolderSelection(accountUuid: String, folderNameKey: String, folderSelectionKey: String) {
36→        val folderName = migrationsHelper.readValue(db, "$accountUuid.$folderNameKey")
37→        val folderSelection = migrationsHelper.readValue(db, "$accountUuid.$folderSelectionKey")
38→
39→        // If folder name is configured (not null and not empty) but selection is AUTOMATIC,
40→        // change it to MANUAL to honor the configured folder
41→        if (!folderName.isNullOrEmpty() && folderSelection == "AUTOMATIC") {
42→            migrationsHelper.writeValue(db, "$accountUuid.$folderSelectionKey", "MANUAL")
43→        }
44→    }
45→}
